import{c as o,Q as t,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Completing Your Profile","description":"","frontmatter":{},"headers":[],"relativePath":"guide/account/completing-your-profile.md","filePath":"guide/account/completing-your-profile.md","lastUpdated":1779094756000}'),i={name:"guide/account/completing-your-profile.md"};function l(s,e,n,u,p,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="completing-your-profile" tabindex="-1">Completing Your Profile <a class="header-anchor" href="#completing-your-profile" aria-label="Permalink to &quot;Completing Your Profile&quot;">​</a></h1><p>If your account was created without a complete profile — for example, you were invited by an operator and the customer requires custom attributes — you will be sent to the <strong>Complete Your Profile</strong> page the first time you sign in.</p><h2 id="what-you-see" tabindex="-1">What you see <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What you see&quot;">​</a></h2><p>The page is a single form titled <strong>Complete Your Profile</strong> with one section per attribute your organisation requires. Fields can be:</p><ul><li>Short text</li><li>Number</li><li>A dropdown (single select) or chip group (multi-select)</li><li>A date (use the date picker)</li><li>An on/off toggle</li></ul><p>Required fields are marked with a red asterisk.</p><h2 id="if-you-belong-to-multiple-customers" tabindex="-1">If you belong to multiple customers <a class="header-anchor" href="#if-you-belong-to-multiple-customers" aria-label="Permalink to &quot;If you belong to multiple customers&quot;">​</a></h2><p>At the top of the form, you will see one badge per customer organisation you belong to. Customers whose profile you have already completed are marked with a green check.</p><ul><li>Fill in the form for the current customer.</li><li>Click <strong>Save &amp; Continue</strong> to move on to the next customer.</li><li>After the last customer, the button changes to <strong>Complete Profile</strong>.</li><li>When all customers are complete, you are sent on to your home page.</li></ul><h2 id="after-you-complete" tabindex="-1">After you complete <a class="header-anchor" href="#after-you-complete" aria-label="Permalink to &quot;After you complete&quot;">​</a></h2><p>If you reached this page from a partner application, you are redirected back to that application. Otherwise, you land on your home page in the Console (Dashboard for operators, Customer Portal Dashboard for customer admins).</p><h2 id="coming-back-to-this-page" tabindex="-1">Coming back to this page <a class="header-anchor" href="#coming-back-to-this-page" aria-label="Permalink to &quot;Coming back to this page&quot;">​</a></h2><p>After your initial profile is set up, your profile is no longer &quot;incomplete&quot; and the page does not appear automatically. To change profile fields later, open your <a href="./managing-your-account">Account</a> page → <strong>User Attributes</strong>.</p><h2 id="if-you-should-not-see-this-page" tabindex="-1">If you should not see this page <a class="header-anchor" href="#if-you-should-not-see-this-page" aria-label="Permalink to &quot;If you should not see this page&quot;">​</a></h2><p>The Complete Profile page only applies to customer users. If you are an internal operator and the page somehow appears, the message <strong>&quot;This page is only available for customer users&quot;</strong> is shown. Sign out and back in, or contact support.</p>',15)])])}const g=o(i,[["render",l]]);export{m as __pageData,g as default};
